 				    &new_vma_flags, NULL_VM_UFFD_CTX,
@@ -2255,6 +2337,14 @@ static int userfaultfd_register_range(struct userfaultfd_ctx *ctx,
 		    vma_test_all_mask(vma, vma_flags))
